all_data = existing + new_data
with open("data/nch_batch.json", "w", encoding="utf-8") as f:
    json.dump(all_data, f, ensure_ascii=False, indent=4)

if os.path.exists("data/niche_batch_1.json"):
    os.remove("data/niche_batch_1.json")

print(f"Niche Total generated: {len(all_data)}")
